prolog_program:
satisfies_inequality(N) :-
    (N > 2 -> false ;
     N =:= 2 -> false ;
     N > -4, N < 2 -> true ;
     N =:= -4 -> false ;
     N < -4 -> false).

count_solutions(Count) :-
    findall(N, (between(-4, 2, N), satisfies_inequality(N)), Solutions),
    length(Solutions, Count).

solve :-
    count_solutions(Count),
    write(Count), nl.

