prolog_program:
max_pair_sum([A,B,C,D], Max) :-
    (A + B >= C + D, A + B >= A + C, A + B >= A + D, A + B >= B + C, A + B >= B + D, A + B >= C + D) -> Max = A + B;
    (A + C >= B + D, A + C >= A + B, A + C >= A + D, A + C >= B + C, A + C >= C + D, A + C >= B + D) -> Max = A + C;
    (A + D >= B + C, A + D >= A + B, A + D >= A + C, A + D >= B + D, A + D >= C + D, A + D >= B + C) -> Max = A + D;
    (B + C >= A + D, B + C >= A + B, B + C >= A + C, B + C >= B + D, B + C >= C + D, B + C >= A + D) -> Max = B + C;
    (B + D >= A + C, B + D >= A + B, B + D >= A + D, B + D >= B + C, B + D >= C + D, B + D >= A + C) -> Max = B + D;
    Max = C + D.

compute_x_y(S, XplusY) :-
    XplusY is 3 * S - 1030.

solve :-
    max_pair_sum([189, 320, 287, 234], S),
    compute_x_y(S, XplusY),
    write(XplusY), nl.

