prolog_program:
normalize_angle(Angle, Normalized) :-
    Normalized is (Angle mod 360),
    (Normalized > 180 -> N is Normalized - 360; N = Normalized),
    (N =< -180 -> M is N + 360; M = N).

solve :-
    normalize_angle(604, N1),
    (N1 =< -90 -> N2 is -180 - N1;
     N1 >= 90 -> N2 is 180 - N1;
     N2 = N1),
    (N2 < -90 -> N3 is N2 + 360;
     N2 > 90 -> N3 is N2 - 360;
     N3 = N2),
    (between(-90, 90, N3) -> N = N3;
     normalize_angle(N3, N4),
     (N4 =< -90 -> N is -180 - N4;
      N4 >= 90 -> N is 180 - N4;
      N = N4)),
    write(N).

