prolog_program:
gcd(X, Y, G) :-
    X = 0 -> G = Y;
    Y = 0 -> G = X;
    X >= Y -> X1 is X mod Y, gcd(Y, X1, G);
    Y1 is Y mod X, gcd(X, Y1, G).

solve :-
    between(1, 100, N),
    N1 is 100 - N,
    gcd(N1, 12, 4),
    write(N1).

