prolog_program:
factors(3774, [2, 3, 17, 37]).

generate_factors([F1, F2, F3, F4], Factor) :-
    (Factor is F1 * F2, Factor >= 10, Factor =< 99);
    (Factor is F1 * F3, Factor >= 10, Factor =< 99);
    (Factor is F1 * F4, Factor >= 10, Factor =< 99);
    (Factor is F2 * F3, Factor >= 10, Factor =< 99);
    (Factor is F2 * F4, Factor >= 10, Factor =< 99);
    (Factor is F3 * F4, Factor >= 10, Factor =< 99);
    (Factor is F1 * F2 * F3, Factor >= 10, Factor =< 99);
    (Factor is F1 * F2 * F4, Factor >= 10, Factor =< 99);
    (Factor is F1 * F3 * F4, Factor >= 10, Factor =< 99);
    (Factor is F2 * F3 * F4, Factor >= 10, Factor =< 99).

find_pairs(Pair) :-
    factors(3774, Factors),
    generate_factors(Factors, A),
    generate_factors(Factors, B),
    A * B =:= 3774,
    A =< B,
    Pair = A.

solve :-
    findall(X, find_pairs(X), Pairs),
    min_list(Pairs, Min),
    write(Min).

